        INSERT INTO TB_BOX_IVT_EXNT_RQST_M
        (
            INVM_EXNT_RQST_ID
            , INVM_CMP_ID
            , RQST_ENPR_ID
            , ANNC_DAT_FILE_ID
            , ADDT_DOC_FILE_ID
            , PBRL_PICT_URL
            , PRPL_MSG_CON
            , RQST_MSG_CON
            , EXNT_MSG_CON
            , INQ_ABL_NDD
            , RGSN_USER_ID
            , RGSN_TS
            , AMNN_USER_ID
            , AMNN_TS

            
            , BRCD
            , EMN
            , EMM
            , TCB_TCHN_GRD
            , INCF_CD1
            , INCF_CD2
            , INCF_CD3
        )
        VALUES
        (
            #{invmExntRqstId}
            , #{invmCmpId}
            , #{rqstEnprId}
            , #{anncDatFileId}
            , #{addtDocFileId}
            , #{pbrlPictUrl}
            , #{prplMsgCon}
            , #{rqstMsgCon}
            , #{exntMsgCon}
            , #{inqAblNdd}
            , #{rgsnUserId}
            , CURRENT_TIMESTAMP
            , #{amnnUserId}
            , CURRENT_TIMESTAMP

            , #{brcd}
            , #{emn}
            , #{emm}
            , #{tcbTchnGrd}
            , #{incfCd1}
            , #{incfCd2}
            , #{incfCd3}
        )

INSERT INTO TB_BOX_IVT_EXNT_PGSG_R
(
    INVM_EXNT_RQST_ID
    , INVM_EXNT_PGSG_CD
    , RGSN_USER_ID
    , RGSN_TS
)
VALUES
(
    #{invmExntRqstId}
    , #{invmExntPgsgCd}
    , #{rgsnUserId}
    , CURRENT_TIMESTAMP
)

