UPDATE
    TB_BOX_IVT_EXNT_RQST_M
SET
    BRCD         		= #{brcd}
    , EMN       		= #{emn}
    , EMM       		= #{emm}
    , AMNN_USER_ID      = #{amnnUserId}
    , AMNN_TS           = CURRENT_TIMESTAMP
WHERE
    INVM_EXNT_RQST_ID = #{invmExntRqstId}
